var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"악마와 마주쳤다고?","JPN":"悪魔と遭遇したって？","ENG":"You met a devil?","TWN":"你說你們遇到魔鬼？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"호박머리를 달고 있는 괴상한 악마였어.","JPN":"カボチャの頭をした、奇怪な悪魔だったよ。","ENG":"He was an odd devil with a pumpkin for a head.","TWN":"是個有著南瓜頭的奇怪魔鬼。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 녀석, 우리를 마치 기다렸다는 듯 나타났다고.","JPN":"あいつはまるで、あたしたちが来るのを待っていたかのように現れたの。","ENG":"It was as if he was waiting for us.","TWN":"那傢伙是早有準備，在等我們出現。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 무사히 돌아온 걸 보니, 루를 함께 보내길 잘 한 모양이네.","JPN":"でも無事に帰ってこれたんだから、やはりルーを一緒に行かせてよかったみたいね。","ENG":"But seeing how you two are back safe, it was a wise choice to send Lugh along.","TWN":"不過既然你們能夠平安回來，看來帶上露是個明智的決定。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐어, 부정하진 않을게. 조금 도움이 되긴 했으니까.","JPN":"まぁ、否定はしないよ。ちょっとは役に立ったから。","ENG":"Well, I won't deny it. She did help a little.","TWN":"嗯，我不否認，確實有點幫助。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"조금만 도움이 된 건가요?","JPN":"ちょっとだけなんですか？","ENG":"Just a little?","TWN":"只是有點幫助嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"조금…","JPN":"それは……","ENG":"A little...","TWN":"有…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아주 많이… 도움이 됐어! 됐지?","JPN":"すごくたくさん……役に立ったわよ！　それでいい？","ENG":"more... than just a helping hand! Happy?","TWN":"非常…大的幫助！可以了吧！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네! 고마워요.","JPN":"はい、ありがとうございます。","ENG":"Yes! Thank you.","TWN":"謝謝你。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쨌든 이번 원정은 실패야.","JPN":"とにかく、今回の遠征は失敗よ。","ENG":"Anyway, this expedition was a bust.","TWN":"總之就結果而言，這次的遠征是失敗的。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"구해온 적철도 계획보다 부족하고, 선발대와 관련된 흔적은 찾지도 못했으니까.","JPN":"入手した赤鉄も計画より少ないし、先発隊に関する痕跡は何一つ見つけられなかったからね。","ENG":"The amount of Violarite we brought was less than what we planned, and we couldn't find any clues related to the advance party.","TWN":"帶回來的赤鐵比預期的還要少，而且也沒找到先遣隊的任何蹤跡。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"흔적도 없었다라…","JPN":"何も痕跡がなかった……か。","ENG":"There wasn't even a trace...","TWN":"連蹤跡都沒有…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어쩌면 너희가 해치웠다는 호박머리 괴물들이 선발대와 연관이 있는 게 아닐까?","JPN":"もしかしたら、アナタたちが追い払ったというカボチャ頭の化け物が、先発隊の失踪と何か関連があるのかもしれないわね。","ENG":"Perhaps those pumpkin-head monsters you defeated have some correlation?","TWN":"你們打倒的那些南瓜頭怪物，會不會和先遣隊有什麼關聯？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼意思…？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇다는 건… 설마 그 악마를 따르는 괴물들이 20년 전의 조사단 사람들이란 건가요?","JPN":"それって……まさかあの悪魔に従っていた化け物たちが、20年前の調査隊の方々ということなんですか？","ENG":"Are you saying... that those monsters following that devil are the survey corps from twenty years ago?","TWN":"你是想說…那些跟隨魔鬼的怪物，是20年前的調查團成員？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐라는 거야! 끔찍한 소리 하지 마!","JPN":"なに言ってるのよ！　とんでもないことを言わないで！","ENG":"Are you kidding me?! Don't say something that terrible!","TWN":"你在說什麼！少說嚇人的話！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"죄, 죄송해요! 너무 멋대로 짚었나?","JPN":"す、すみません。行き過ぎた憶測でした。","ENG":"I-I'm sorry! Did my imagination go too far?","TWN":"對…對不起！是我太天馬行空？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 귀염둥이. 너도 배워서 알고 있잖니?","JPN":"でも可愛子ちゃん。アナタもそう習ったでしょう？","ENG":"But cutie, you were also taught, so you know.","TWN":"但是小可愛，你也學過這些，不是嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"악마는 인간의 영혼을 갈취하고 계약을 통해 자신의 하수인으로 부린다는 걸 말이야.","JPN":"悪魔は人の魂を喰らい、契約によって自分のしもべにしてしまうと。","ENG":"A devil extorts human souls and makes them his servants through contracts.","TWN":"魔鬼會掠奪人類的靈魂，藉由契約將人類變成自己的僕人。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그게 사실이라면, 주민들에겐 말하지 않는 게 좋겠어.","JPN":"もしそれが本当なら、住民たちには言わない方がいいね。","ENG":"If that's true, I think it's best not to tell the villagers.","TWN":"如果那是真的，那最好不要告訴村民。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자기 가족이 괴물이 됐다는 소식을 기다리던 사람은 없을 테니까.","JPN":"自分の家族が化け物になったなんて聞きたくないはずだから。","ENG":"No one will want to hear that their loved ones have turned into monsters.","TWN":"沒有人會想聽到自己家人變成怪物的消息。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래. 그런 진실이라면, 차라리 모르는 편이 나을지도 모르겠네.","JPN":"そうね。それが本当なら、知らない方がいいかもしれないわね。","ENG":"Yes. If that is the truth, it is best not to know.","TWN":"沒錯，如果若真相是如此，倒不如不要知道。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래도, 너희가 무사히 돌아와서 다행이야.","JPN":"でも、アナタたちが無事帰ってきてくれて、本当によかったわ。","ENG":"Nevertheless, I am glad you are back safe.","TWN":"不過，至少這次大家都平安回來。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"실패를 만회할 기회는 다음에도 있으니까.","JPN":"失敗を挽回するチャンスは次回もあるしね。","ENG":"There are still more opportunities to make up for failure.","TWN":"下次還有機會彌補失敗。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기… 실례지만, 그루터기에 이런 무기를 고쳐 주시는 분도 있을까요?","JPN":"あの……すみません。切り株にこういった武器を直せる方っていらっしゃいますか？","ENG":"Um... I'm sorry to interrupt, but is there someone who can repair this weapon in the Stump?","TWN":"那個…打斷一下，這裡有人能修理我的武器嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어머, 원정 도중에 고장 난 거니?","JPN":"あら、遠征中に壊れちゃったの？","ENG":"Oh, my. Did it break during the expedition?","TWN":"哎呀，是在遠征途中壞掉的嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};